// ============================================================
// CONFIGURATION — edit all parameters here
// ============================================================

const DEVICE_ID = 'b6930861fd4fcd8ce162a7643da311f5';

// Timezone for schedule evaluation.
// Node-RED in Docker typically runs UTC even if your house is CET/CEST.
// Set this to your IANA timezone name so the schedule follows wall-clock time.
const TIMEZONE = 'Europe/Brussels';

// Default mode: schedule time slots.
// Each slot: { startHour, endHour, maxA }
// startHour inclusive, endHour exclusive (24-hour format).
// maxA = the guaranteed minimum charging speed within this window.
// If solar is exporting, the current can rise above maxA (up to SOLAR_MAX_A).
const SCHEDULE_WEEKDAY = [
    { startHour: 1, endHour: 7, maxA: 16 }
];

const SCHEDULE_WEEKEND = [
    { startHour: 1,  endHour: 7,  maxA: 16 },
    { startHour: 11, endHour: 17, maxA: 16 }
];

// Absolute maximum that solar surplus may ramp up to in Default mode.
const SOLAR_MAX_A = 32;

// Maximum current for Boost mode (session-only).
const BOOST_MAX_A = 32;

// Solar only mode: current range (session-only).
// Min = 0 so the car pauses completely when no solar is available.
const SOLAR_ONLY_MIN_A = 0;
const SOLAR_ONLY_MAX_A = 32;

// Target net export in watts. The algorithm aims to keep the house exporting
// exactly this many watts after adjusting the charging current.
// Higher = more buffer/slower to react to export; lower = tighter tracking.
const SOLAR_MARGIN_W = 400;

// Mains voltage (V) used to convert watts to amps.
// 230 V for single-phase European installations.
const PHASE_VOLTAGE = 230;

// Sliding window: the "Get P1 history" node fetches all P1 state changes
// from the HA recorder. The window duration is set on that node (relativeTime).
// The Brain computes a time-weighted average of whatever history arrives.
// To change the window, update the relativeTime field on "Get P1 history".

// ============================================================
// LOGIC — no need to edit below this line
// ============================================================

const mode     = msg.mode;
let   setpoint = Number(msg.current_setpoint); // A

if (isNaN(setpoint)) {
    node.warn('Invalid setpoint — skipping tick');
    return null;
}

function getLocalTime() {
    // Intl.DateTimeFormat with explicit TIMEZONE so the schedule follows
    // wall-clock time regardless of the Node-RED host system timezone (UTC in Docker).
    const parts = new Intl.DateTimeFormat('en-GB', {
        timeZone: TIMEZONE, weekday: 'short',
        hour: '2-digit', minute: '2-digit', hour12: false
    }).formatToParts(new Date());
    const get = type => parts.find(p => p.type === type).value;
    let hour = parseInt(get('hour'), 10);
    if (hour === 24) hour = 0; // guard: some JS engines return 24 for midnight
    return {
        hour:      hour + parseInt(get('minute'), 10) / 60,
        isWeekend: ['Sat', 'Sun'].includes(get('weekday'))
    };
}

function clamp(v, min, max) {
    return Math.max(min, Math.min(max, Math.round(v)));
}

// Time-weighted average of P1 over the history window.
// msg.payload is an array of HA history objects: [{ state, last_changed }, ...]
// sorted oldest-first. Each value is weighted by how long it was active before
// the next change. The final value runs up to now.
function timeWeightedAvgP1(history) {
    if (!Array.isArray(history) || history.length === 0) {
        node.warn('Empty P1 history — skipping tick');
        return null;
    }
    const now = Date.now();
    let weightedSum = 0;
    let totalMs     = 0;
    for (let i = 0; i < history.length; i++) {
        const val  = parseFloat(history[i].state);
        if (isNaN(val)) continue;                          // skip unavailable/unknown
        const from = new Date(history[i].last_changed).getTime();
        const to   = i + 1 < history.length
                     ? new Date(history[i + 1].last_changed).getTime()
                     : now;
        const ms   = Math.max(0, to - from);
        weightedSum += val * ms;
        totalMs     += ms;
    }
    if (totalMs === 0) {
        node.warn('P1 history has no duration — skipping tick');
        return null;
    }
    return weightedSum / totalMs;
}

const avgP1 = timeWeightedAvgP1(msg.payload);
if (avgP1 === null) return null;

// Direct target calculation.
// We want the house to export SOLAR_MARGIN_W watts after the adjustment.
// Desired P1 = -SOLAR_MARGIN_W  →  delta needed = (-SOLAR_MARGIN_W - avgP1) / PHASE_VOLTAGE
//   avgP1 = +500 W (importing 500 W): delta = (-400 - 500) / 230 ≈ -3.9 A  → slow down
//   avgP1 = -800 W (exporting 800 W): delta = (-400 - -800) / 230 ≈ +1.7 A → speed up
//   avgP1 = -400 W (exactly on target): delta = 0 A                         → no change
function targetA(currentA, floorA, maxA) {
    const deltaA = (-SOLAR_MARGIN_W - avgP1) / PHASE_VOLTAGE;
    return clamp(currentA + deltaA, floorA, maxA);
}

// --- Default mode: schedule-following + solar tracking ---
// Inside a schedule window: floor = slot.maxA. Solar can ramp above it toward SOLAR_MAX_A.
// Outside every window:     floor = 0 A. Solar can still charge; drops to 0 when no export.
if (mode === 'Default') {
    const { hour: localHour, isWeekend } = getLocalTime();
    const schedule = isWeekend ? SCHEDULE_WEEKEND : SCHEDULE_WEEKDAY;
    const slot     = schedule.find(s => localHour >= s.startHour && localHour < s.endHour) || null;
    const floor    = slot ? slot.maxA : 0; // guaranteed minimum inside window; 0 outside
    msg.payload = { new_current: targetA(setpoint, floor, SOLAR_MAX_A), device_id: DEVICE_ID };
    return msg;
}

// --- Boost mode (session-only) ---
// Charges at BOOST_MAX_A immediately, ignoring schedule and solar.
// Automatically resets to Default when the car unplugs.
if (mode === 'Boost') {
    msg.payload = { new_current: BOOST_MAX_A, device_id: DEVICE_ID };
    return msg;
}

// --- Solar only mode (session-only) ---
// Tracks solar export; pauses (0 A) when no solar is available.
// Automatically resets to Default when the car unplugs.
if (mode === 'Solar only') {
    msg.payload = { new_current: targetA(setpoint, SOLAR_ONLY_MIN_A, SOLAR_ONLY_MAX_A), device_id: DEVICE_ID };
    return msg;
}

node.warn('Unknown mode: ' + mode);
return null;
